#graphql
  query MetaobjectDefinitionsForLimitCaps($first: Int!, $after: String) {
    metaobjectDefinitions(first: $first, after: $after) {
      nodes {
        id
        type
        name
        standardTemplate {
          type
          name
        }
      }
      pageInfo {
        hasNextPage
        endCursor
      }
    }
  }
